function getLocalizedSource(source: string, locale: Locale) {
  if (locale === 'hy') return source;
  if (locale === 'ru' && russianOverrides[source]) return russianOverrides[source];
  return contentTranslations[source]?.[locale] ?? source;
}

function findTranslationSource(value: string) {
  if (contentTranslations[value]) return value;

  return Object.entries(contentTranslations).find(([source, translations]) => (
    translations.en === value ||
    translations.ru === value ||
    russianOverrides[source] === value
  ))?.[0];
}

export function localizeContent(value: string, locale: Locale) {
  const exactSource = findTranslationSource(value);
  if (exactSource) return getLocalizedSource(exactSource, locale);

  const variants = Object.entries(contentTranslations).flatMap(([source, translations]) => [
    { source, value: source },
    { source, value: translations.en },
    { source, value: translations.ru },
    ...(russianOverrides[source] ? [{ source, value: russianOverrides[source] }] : []),
  ]);

  return variants
    .filter((item) => item.value)
    .sort((first, second) => second.value.length - first.value.length)
    .reduce((localized, item) => localized.replaceAll(item.value, getLocalizedSource(item.source, locale)), value);
}
